  1	import * as React from 'react';
  2	import {
  3	  EnrollDiscoveredApplicationStepNames,
  4	  EnrollDiscoveredApplicationSteps,
  5	  DR_BASE_ROUTE,
  6	} from '@odf/mco/constants';
  7	import PageHeading from '@odf/shared/heading/page-heading';
  8	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  9	import { TFunction } from 'react-i18next';
 10	import { useNavigate } from 'react-router-dom-v5-compat';
 11	import {
 12	  Text,
 13	  TextContent,
 14	  TextVariants,
 15	  Wizard,
 16	  WizardStep,
 17	  WizardStepProps,
 18	} from '@patternfly/react-core';
 19	import { EnrollDiscoveredApplicationFooter } from './footer';
 20	import { createPromise } from './utils/k8s-utils';
 21	import {
 22	  EnrollDiscoveredApplicationState,
 23	  EnrollDiscoveredApplicationAction,
 24	  EnrollReducer,
 25	  reducer,
 26	  initialState,
 27	} from './utils/reducer';
 28	import {
 29	  NamespaceSelection,
 30	  Configuration,
 31	  ReplicationSelection,
 32	  Review,
 33	} from './wizard-steps';
 34	import './enroll-discovered-application.scss';
 35	
 36	const breadcrumbs = (t: TFunction) => [
 37	  {
 38	    name: t('Protected applications'),
 39	    path: `${DR_BASE_ROUTE}/protected-applications`,
 40	  },
 41	  {
 42	    name: t('Enroll discovered application'),
 43	    path: '',
 44	  },
 45	];
 46	
 47	export const createSteps = (
 48	  state: EnrollDiscoveredApplicationState,
 49	  isValidationEnabled: boolean,
 50	  dispatch: React.Dispatch<EnrollDiscoveredApplicationAction>,
 51	  t: TFunction
 52	): (Pick<WizardStepProps, 'id' | 'name'> & {
 53	  component: React.ReactElement;
 54	})[] => [
 55	  {
 56	    id: 1,
 57	    name: EnrollDiscoveredApplicationStepNames(t)[
 58	      EnrollDiscoveredApplicationSteps.Namespace
 59	    ],
 60	    component: (
 61	      <NamespaceSelection
 62	        state={state}
 63	        isValidationEnabled={isValidationEnabled}
 64	        dispatch={dispatch}
 65	      />
 66	    ),
 67	  },
 68	  {
 69	    id: 2,
 70	    name: EnrollDiscoveredApplicationStepNames(t)[
 71	      EnrollDiscoveredApplicationSteps.Configuration
 72	    ],
 73	    component: (
 74	      <Configuration
 75	        state={state}
 76	        isValidationEnabled={isValidationEnabled}
 77	        dispatch={dispatch}
 78	      />
 79	    ),
 80	  },
 81	  {
 82	    id: 3,
 83	    name: EnrollDiscoveredApplicationStepNames(t)[
 84	      EnrollDiscoveredApplicationSteps.Replication
 85	    ],
 86	    component: (
 87	      <ReplicationSelection
 88	        state={state}
 89	        isValidationEnabled={isValidationEnabled}
 90	        dispatch={dispatch}
 91	      />
 92	    ),
 93	  },
 94	  {
 95	    id: 4,
 96	    name: EnrollDiscoveredApplicationStepNames(t)[
 97	      EnrollDiscoveredApplicationSteps.Review
 98	    ],
 99	    component: <Review state={state} />,
100	  },
101	];
102	
103	const EnrollDiscoveredApplication: React.FC<{}> = () => {
104	  const { t } = useCustomTranslation();
105	  const navigate = useNavigate();
106	  const [isValidationEnabled, setIsValidationEnabled] = React.useState(false);
107	  const [onSaveError, setOnSaveError] = React.useState('');
108	
109	  const [state, dispatch] = React.useReducer<EnrollReducer>(
110	    reducer,
111	    initialState
112	  );
113	
114	  const title = t('Enroll discovered application');
115	
116	  const onSubmit = async (
117	    setRequestInProgress: React.Dispatch<React.SetStateAction<boolean>>
118	  ) => {
119	    setRequestInProgress(true);
120	    const promises = createPromise(state);
121	    await Promise.all(promises)
122	      .then(() => {
123	        navigate(
124	          `${DR_BASE_ROUTE}/protected-applications?enrolledApp=${state.namespace.name}`
125	        );
126	      })
127	      .catch((error) => {
128	        setOnSaveError(error?.message);
129	        setRequestInProgress(false);
130	      });
131	  };
132	
133	  const steps = createSteps(state, isValidationEnabled, dispatch, t);
134	
135	  return (
136	    <>
137	      <PageHeading title={title} breadcrumbs={breadcrumbs(t)}>
138	        <TextContent>
139	          <Text component={TextVariants.small}>
140	            {t(
141	              'Enroll your applications to improve resilience by implementing disaster recovery protection.'
142	            )}
143	          </Text>
144	        </TextContent>
145	      </PageHeading>
146	      <Wizard
147	        className="mco-enroll-discovered-application__wizard--height"
148	        navAriaLabel={t('Enroll discovered application nav')}
149	        isVisitRequired
150	        footer={
151	          <EnrollDiscoveredApplicationFooter
152	            state={state}
153	            isValidationEnabled={isValidationEnabled}
154	            onSaveError={onSaveError}
155	            setIsValidationEnabled={setIsValidationEnabled}
156	            onSubmit={onSubmit}
157	            onCancel={() => navigate(-1)}
158	          />
159	        }
160	      >
161	        {steps.map((step) => (
162	          <WizardStep key={step.id} id={step.id} name={step.name}>
163	            {step.component}
164	          </WizardStep>
165	        ))}
166	      </Wizard>
167	    </>
168	  );
169	};
170	
171	export default EnrollDiscoveredApplication;

