  1	import * as React from 'react';
  2	import {
  3	  EnrollDiscoveredApplicationStepNames,
  4	  EnrollDiscoveredApplicationSteps,
  5	  DR_BASE_ROUTE,
  6	} from '@odf/mco/constants';
  7	import PageHeading from '@odf/shared/heading/page-heading';
  8	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  9	import { TFunction } from 'react-i18next';
 10	import { useNavigate } from 'react-router-dom-v5-compat';
 11	import {
 12	  Content,
 13	  ContentVariants,
 14	  Wizard,
 15	  WizardStep,
 16	  WizardStepProps,
 17	} from '@patternfly/react-core';
 18	import { EnrollDiscoveredApplicationFooter } from './footer';
 19	import { createPromise } from './utils/k8s-utils';
 20	import {
 21	  EnrollDiscoveredApplicationState,
 22	  EnrollDiscoveredApplicationAction,
 23	  EnrollReducer,
 24	  reducer,
 25	  initialState,
 26	} from './utils/reducer';
 27	import {
 28	  NamespaceSelection,
 29	  Configuration,
 30	  ReplicationSelection,
 31	  Review,
 32	} from './wizard-steps';
 33	import './enroll-discovered-application.scss';
 34	
 35	const breadcrumbs = (t: TFunction) => [
 36	  {
 37	    name: t('Protected applications'),
 38	    path: `${DR_BASE_ROUTE}/protected-applications`,
 39	  },
 40	  {
 41	    name: t('Enroll discovered application'),
 42	    path: '',
 43	  },
 44	];
 45	
 46	export const createSteps = (
 47	  state: EnrollDiscoveredApplicationState,
 48	  isValidationEnabled: boolean,
 49	  dispatch: React.Dispatch<EnrollDiscoveredApplicationAction>,
 50	  t: TFunction
 51	): (Pick<WizardStepProps, 'id' | 'name'> & {
 52	  component: React.ReactElement;
 53	})[] => [
 54	  {
 55	    id: 1,
 56	    name: EnrollDiscoveredApplicationStepNames(t)[
 57	      EnrollDiscoveredApplicationSteps.Namespace
 58	    ],
 59	    component: (
 60	      <NamespaceSelection
 61	        state={state}
 62	        isValidationEnabled={isValidationEnabled}
 63	        dispatch={dispatch}
 64	      />
 65	    ),
 66	  },
 67	  {
 68	    id: 2,
 69	    name: EnrollDiscoveredApplicationStepNames(t)[
 70	      EnrollDiscoveredApplicationSteps.Configuration
 71	    ],
 72	    component: (
 73	      <Configuration
 74	        state={state}
 75	        isValidationEnabled={isValidationEnabled}
 76	        dispatch={dispatch}
 77	      />
 78	    ),
 79	  },
 80	  {
 81	    id: 3,
 82	    name: EnrollDiscoveredApplicationStepNames(t)[
 83	      EnrollDiscoveredApplicationSteps.Replication
 84	    ],
 85	    component: (
 86	      <ReplicationSelection
 87	        state={state}
 88	        isValidationEnabled={isValidationEnabled}
 89	        dispatch={dispatch}
 90	      />
 91	    ),
 92	  },
 93	  {
 94	    id: 4,
 95	    name: EnrollDiscoveredApplicationStepNames(t)[
 96	      EnrollDiscoveredApplicationSteps.Review
 97	    ],
 98	    component: <Review state={state} />,
 99	  },
100	];
101	
102	const EnrollDiscoveredApplication: React.FC<{}> = () => {
103	  const { t } = useCustomTranslation();
104	  const navigate = useNavigate();
105	  const [isValidationEnabled, setIsValidationEnabled] = React.useState(false);
106	  const [onSaveError, setOnSaveError] = React.useState('');
107	
108	  const [state, dispatch] = React.useReducer<EnrollReducer>(
109	    reducer,
110	    initialState
111	  );
112	
113	  const title = t('Enroll discovered application');
114	
115	  const onSubmit = async (
116	    setRequestInProgress: React.Dispatch<React.SetStateAction<boolean>>
117	  ) => {
118	    setRequestInProgress(true);
119	    const promises = createPromise(state);
120	    await Promise.all(promises)
121	      .then(() => {
122	        navigate(
123	          `${DR_BASE_ROUTE}/protected-applications?enrolledApp=${state.namespace.name}`
124	        );
125	      })
126	      .catch((error) => {
127	        setOnSaveError(error?.message);
128	        setRequestInProgress(false);
129	      });
130	  };
131	
132	  const steps = createSteps(state, isValidationEnabled, dispatch, t);
133	
134	  return (
135	    <>
136	      <PageHeading title={title} breadcrumbs={breadcrumbs(t)}>
137	        <Content component={ContentVariants.small}>
138	          {t(
139	            'Enroll your applications to improve resilience by implementing disaster recovery protection.'
140	          )}
141	        </Content>
142	      </PageHeading>
143	      <Wizard
144	        className="mco-enroll-discovered-application__wizard--height"
145	        navAriaLabel={t('Enroll discovered application nav')}
146	        isVisitRequired
147	        footer={
148	          <EnrollDiscoveredApplicationFooter
149	            state={state}
150	            isValidationEnabled={isValidationEnabled}
151	            onSaveError={onSaveError}
152	            setIsValidationEnabled={setIsValidationEnabled}
153	            onSubmit={onSubmit}
154	            onCancel={() => navigate(-1)}
155	          />
156	        }
157	      >
158	        {steps.map((step) => (
159	          <WizardStep key={step.id} id={step.id} name={step.name}>
160	            {step.component}
161	          </WizardStep>
162	        ))}
163	      </Wizard>
164	    </>
165	  );
166	};
167	
168	export default EnrollDiscoveredApplication;

